static void c33(const float*i,float*o,int H,int W,int ic,int oc,const float*w,const float*b){
int HW=H*W;for(int p=0;p<oc;p++){float B=b[p];float*op=o+p*HW;for(int j=0;j<HW;j++)op[j]=B;}
for(int c=0;c<ic;c++){const float*ip=i+c*HW;for(int p=0;p<oc;p++){float*op=o+p*HW;const float*wp=w+p*ic*9+c*9;
for(int y=0;y<H;y++)for(int x=0;x<W;x++){float s=0;for(int ky=-1;ky<=1;ky++){int iy=y+ky;if((unsigned)iy>=(unsigned)H)continue;for(int kx=-1;kx<=1;kx++){int ix=x+kx;if((unsigned)ix>=(unsigned)W)continue;s+=ip[iy*W+ix]*wp[(ky+1)*3+(kx+1)];}}op[y*W+x]+=s;}}}}
static void dw(const float*i,float*o,int H,int W,int ch,const float*w,const float*b){
int HW=H*W;for(int c=0;c<ch;c++){float B=b[c];for(int y=0;y<H;y++)for(int x=0;x<W;x++){float s=B;for(int ky=-1;ky<=1;ky++){int iy=y+ky;if((unsigned)iy>=(unsigned)H)continue;for(int kx=-1;kx<=1;kx++){int ix=x+kx;if((unsigned)ix>=(unsigned)W)continue;s+=i[c*HW+iy*W+ix]*w[c*9+(ky+1)*3+(kx+1)];}}o[c*HW+y*W+x]=s;}}}
static void pw(const float*i,float*o,int H,int W,int ic,int oc,const float*w,const float*b){
int HW=H*W;for(int p=0;p<oc;p++){float B=b[p];float*op=o+p*HW;for(int j=0;j<HW;j++)op[j]=B;}
for(int c=0;c<ic;c++){const float*ip=i+c*HW;for(int p=0;p<oc;p++){float wt=w[p*ic+c];float*op=o+p*HW;for(int j=0;j<HW;j++)op[j]+=ip[j]*wt;}}}
static void rl(float*d,int n){for(int i=0;i<n;i++)if(d[i]<0)d[i]=0;}
static void mp(const float*i,float*o,int H,int W,int C){
int oH=H/2,oW=W/2,iHW=H*W,oHW=oH*oW;for(int c=0;c<C;c++)for(int y=0;y<oH;y++)for(int x=0;x<oW;x++){int iy=y*2,ix=x*2;float v=i[c*iHW+iy*W+ix];v=max(v,i[c*iHW+iy*W+ix+1]);v=max(v,i[c*iHW+(iy+1)*W+ix]);v=max(v,i[c*iHW+(iy+1)*W+ix+1]);o[c*oHW+y*oW+x]=v;}}
static void ct(const float*i,float*o,int iH,int iW,int ic,int oc,const float*w,const float*b){
int oH=iH*2,oW=iW*2,oHW=oH*oW,iHW=iH*iW;for(int p=0;p<oc;p++)for(int j=0;j<oHW;j++)o[p*oHW+j]=b[p];for(int ci=0;ci<ic;ci++)for(int iy=0;iy<iH;iy++)for(int ix=0;ix<iW;ix++){float v=i[ci*iHW+iy*iW+ix];int oy=iy*2,ox=ix*2;for(int p=0;p<oc;p++)for(int ky=0;ky<2;ky++)for(int kx=0;kx<2;kx++)o[p*oHW+(oy+ky)*oW+(ox+kx)]+=v*w[ci*oc*4+p*4+ky*2+kx];}}
static void ap(const float*i,float*o,int H,int W,int C,int tH,int tW){
for(int c=0;c<C;c++)for(int oh=0;oh<tH;oh++){int h0=oh*H/tH,h1=(oh+1)*H/tH;for(int ow=0;ow<tW;ow++){int w0=ow*W/tW,w1=(ow+1)*W/tW;float s=0;int n=0;for(int y=h0;y<h1;y++)for(int x=w0;x<w1;x++){s+=i[c*H*W+y*W+x];n++;}o[c*tH*tW+oh*tW+ow]=s/n;}}}
static void cc(const float*a,const float*b,float*o,int H,int W,int ca,int cb){int HW=H*W;memcpy(o,a,ca*HW*4);memcpy(o+ca*HW,b,cb*HW*4);}
static void ln(const float*i,float*o,int ic,int oc,const float*w,const float*b){for(int p=0;p<oc;p++){float s=b[p];for(int j=0;j<ic;j++)s+=i[j]*w[p*ic+j];o[p]=s;}}
static void sp(const float*i,float*t,float*o,int H,int W,int ic,int oc,int di,int dbi,int pi,int pbi){dw(i,t,H,W,ic,Wp[di],Bp[dbi]);pw(t,o,H,W,ic,oc,Wp[pi],Bp[pbi]);rl(o,oc*H*W);}
